package v1alpha1

import (
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"

package api

import (
	"encoding/json"
	"fmt"

	"k8s.io/apimachinery/pkg/util/sets"
)

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

func (r *CreateSandboxRequest) Validate() error {
	validKinds := sets.NewString("AgentRuntime", "CodeInterpreter")
	if !validKinds.Has(r.Kind) {
		return fmt.Errorf("kind must be one of AgentRuntime or CodeInterpreter")
	}

package api

import (
	"errors"
	"fmt"

	"k8s.io/apimachinery/pkg/runtime/schema"
)

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("template missing")
	ErrPublicKeyMissing        = errors.New("public key missing")
)

type APIStatus interface {
	Status() string
	Message() string
	Reason() string
